import{_ as t,o as r,c as a,a5 as o}from"./chunks/framework.De5lvF_N.js";const m=JSON.parse('{"title":"Observability","description":"","frontmatter":{},"headers":[],"relativePath":"concepts/observability.md","filePath":"concepts/observability.md"}'),i={name:"concepts/observability.md"};function s(l,e,n,c,h,p){return r(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="observability" tabindex="-1">Observability <a class="header-anchor" href="#observability" aria-label="Permalink to &quot;Observability&quot;">​</a></h1><p>Platform Mesh provides telemetry collection infrastructure to help operators monitor the health and performance of their Platform Mesh installation. The observability architecture separates collection from storage, giving operators flexibility to integrate with their existing monitoring systems.</p><h2 id="collection-vs-storage" tabindex="-1">Collection vs. storage <a class="header-anchor" href="#collection-vs-storage" aria-label="Permalink to &quot;Collection vs. storage&quot;">​</a></h2><p>Platform Mesh takes an opinionated approach to observability: it owns the collection side but leaves storage to operators.</p><p><strong>Platform Mesh provides:</strong></p><ul><li>ServiceMonitors that define what metrics to scrape from each component</li><li>An OpenTelemetry Collector that aggregates metrics and traces</li><li>A Target Allocator that discovers scrape targets</li><li>Prometheus remote write and OTLP exporters for forwarding telemetry</li></ul><p><strong>Operators provide:</strong></p><ul><li>A metrics backend (Prometheus, Thanos, Mimir, Cortex, or a cloud provider solution)</li><li>A trace backend (Jaeger, Tempo, or any OTLP-compatible system)</li><li>Long-term storage and retention policies</li><li>Alerting rules and notification channels</li><li>Dashboards and visualization</li></ul><p>This separation exists for several reasons:</p><ol><li><p><strong>Enterprise integration</strong> – Most organizations already have monitoring infrastructure. Platform Mesh integrates with what exists rather than requiring a parallel stack.</p></li><li><p><strong>Flexibility</strong> – Operators choose their storage backend, retention policies, and high-availability setup based on their requirements.</p></li><li><p><strong>Resource efficiency</strong> – Running a production-grade metrics backend requires significant resources. Operators can share infrastructure across multiple Platform Mesh installations or other workloads.</p></li><li><p><strong>Operational ownership</strong> – Metrics storage, backup, and scaling are operational concerns that belong with the team running the infrastructure.</p></li></ol><p>For development and testing, Platform Mesh includes a bundled Prometheus instance for metrics. This instance is configured for convenience, not production use – it has no persistent storage by default and is not configured for high availability.</p><h2 id="what-platform-mesh-collects" tabindex="-1">What Platform Mesh collects <a class="header-anchor" href="#what-platform-mesh-collects" aria-label="Permalink to &quot;What Platform Mesh collects&quot;">​</a></h2><p>Platform Mesh collects telemetry from its core components:</p><h3 id="metrics" tabindex="-1">Metrics <a class="header-anchor" href="#metrics" aria-label="Permalink to &quot;Metrics&quot;">​</a></h3><p>Platform Mesh scrapes Prometheus-format metrics from four categories of components:</p><p><strong>Control plane metrics</strong> – The kcp control plane exposes metrics about workspace operations, API request handling, and internal state. These help operators understand control plane load and identify performance bottlenecks. Scraping kcp requires client certificate authentication, which the observability stack handles automatically.</p><p><strong>Operator metrics</strong> – The account-operator and security-operator expose standard controller-runtime metrics, including reconciliation counts, queue depths, and error rates.</p><p><strong>Authorization metrics</strong> – OpenFGA exposes metrics about authorization check latency, cache hit rates, and store operations.</p><h3 id="traces" tabindex="-1">Traces <a class="header-anchor" href="#traces" aria-label="Permalink to &quot;Traces&quot;">​</a></h3><p>Platform Mesh components can emit distributed traces via OTLP (OpenTelemetry Protocol). Traces help operators debug request flows across components and identify latency bottlenecks.</p><p>Tracing is disabled by default and must be enabled per-component. When enabled, components send spans to the OpenTelemetry Collector, which forwards them to the configured trace backend.</p><h3 id="what-is-not-collected" tabindex="-1">What is not collected <a class="header-anchor" href="#what-is-not-collected" aria-label="Permalink to &quot;What is not collected&quot;">​</a></h3><p>Platform Mesh does not currently collect:</p><ul><li>Application-level metrics from provider workloads</li><li>Network traffic metrics</li><li>Resource usage metrics (CPU, memory) – these come from standard Kubernetes monitoring</li></ul><h2 id="opentelemetry-architecture" tabindex="-1">OpenTelemetry architecture <a class="header-anchor" href="#opentelemetry-architecture" aria-label="Permalink to &quot;OpenTelemetry architecture&quot;">​</a></h2><p>Platform Mesh uses OpenTelemetry as its telemetry collection framework. OpenTelemetry provides a vendor-neutral way to collect, process, and export metrics and traces.</p><h3 id="opentelemetry-operator" tabindex="-1">OpenTelemetry Operator <a class="header-anchor" href="#opentelemetry-operator" aria-label="Permalink to &quot;OpenTelemetry Operator&quot;">​</a></h3><p>The OpenTelemetry Operator manages collector instances declaratively. It handles collector deployment, configuration updates, and scaling. The operator also manages the Target Allocator that distributes scrape targets across collector replicas.</p><h3 id="target-allocator" tabindex="-1">Target Allocator <a class="header-anchor" href="#target-allocator" aria-label="Permalink to &quot;Target Allocator&quot;">​</a></h3><p>The Target Allocator watches ServiceMonitor resources and discovers scrape targets. It distributes targets across collector replicas to balance load and avoid duplicate scraping. This approach scales better than static scrape configurations as the number of targets grows.</p><h3 id="collector-as-aggregation-point" tabindex="-1">Collector as aggregation point <a class="header-anchor" href="#collector-as-aggregation-point" aria-label="Permalink to &quot;Collector as aggregation point&quot;">​</a></h3><p>The OpenTelemetry Collector serves as the central aggregation point for all telemetry:</p><ul><li><strong>Metrics</strong> – The collector scrapes Prometheus endpoints (via Target Allocator), batches metrics, and forwards them via Prometheus remote write.</li><li><strong>Traces</strong> – The collector receives spans via OTLP from instrumented components, batches them, and forwards to trace backends.</li></ul><p>Batching reduces network overhead when sending telemetry to remote backends. The collector can also perform filtering, relabeling, and other transformations before forwarding.</p><h2 id="integration-patterns" tabindex="-1">Integration patterns <a class="header-anchor" href="#integration-patterns" aria-label="Permalink to &quot;Integration patterns&quot;">​</a></h2><p>Operators typically integrate Platform Mesh telemetry using these patterns:</p><h3 id="metrics-prometheus-remote-write" tabindex="-1">Metrics: Prometheus remote write <a class="header-anchor" href="#metrics-prometheus-remote-write" aria-label="Permalink to &quot;Metrics: Prometheus remote write&quot;">​</a></h3><p>The most common pattern – configure the OTel Collector to forward metrics to a Prometheus-compatible backend via the remote write API. This works with:</p><ul><li>Self-hosted Prometheus with remote write receiver enabled</li><li>Thanos Receive</li><li>Grafana Mimir</li><li>Cortex</li><li>Cloud provider managed services (Amazon Managed Prometheus, Google Cloud Managed Prometheus, Azure Monitor)</li></ul><h3 id="traces-otlp-export" tabindex="-1">Traces: OTLP export <a class="header-anchor" href="#traces-otlp-export" aria-label="Permalink to &quot;Traces: OTLP export&quot;">​</a></h3><p>Configure the OTel Collector to forward traces to any OTLP-compatible backend:</p><ul><li>Jaeger</li><li>Grafana Tempo</li><li>Honeycomb</li><li>Lightstep</li><li>Cloud provider tracing services</li></ul><h3 id="metrics-federation" tabindex="-1">Metrics: Federation <a class="header-anchor" href="#metrics-federation" aria-label="Permalink to &quot;Metrics: Federation&quot;">​</a></h3><p>If your existing Prometheus cannot receive remote writes, configure it to federate metrics from the bundled development Prometheus. This pattern is less efficient but works with older Prometheus setups.</p><h3 id="metrics-direct-scraping" tabindex="-1">Metrics: Direct scraping <a class="header-anchor" href="#metrics-direct-scraping" aria-label="Permalink to &quot;Metrics: Direct scraping&quot;">​</a></h3><p>For maximum control, configure your existing Prometheus to scrape Platform Mesh component endpoints directly. The ServiceMonitors in the observability namespace document available targets and authentication requirements. This bypasses the OTel Collector entirely.</p><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="/pr-preview/pr-235/reference/components/observability.html">Observability reference</a></li><li><a href="/pr-preview/pr-235/how-to-guides/access-observability.html">Access the observability stack</a></li><li><a href="/pr-preview/pr-235/concepts/architecture.html">Architecture</a></li></ul>',48)])])}const u=t(i,[["render",s]]);export{m as __pageData,u as default};
